    19→<body>
    20→  <header class="header">
    21→    <div class="container">
    22→      <h1 class="header-title">{{portfolioTitle}}</h1>
    23→      <p class="header-meta">Created {{createdAt}}</p>
    24→    </div>
    25→  </header>
    26→
    27→  <main class="container">
    28→    <div class="prompts-grid">
    29→      {{promptCards}}
    30→    </div>
    31→
    32→    <section class="share-section">
    33→      <p>Share this portfolio</p>
    34→      <div class="share-buttons">
    35→        <button class="btn btn-share" onclick="sharePortfolio()">Share</button>
    36→        <button class="btn btn-copy" onclick="copyLink()">Copy Link</button>
    37→      </div>
    38→    </section>
    39→  </main>
    40→
    41→  <footer class="footer">
    42→    <div class="container">
    43→      <p>Built with Promptfolio</p>
    44→    </div>
    45→  </footer>
    46→
    47→  <script>
    48→    async function sharePortfolio() {
    49→      if (navigator.share) {
    50→        try {
    51→          await navigator.share({
    52→            title: '{{portfolioTitle}}',
    53→            text: 'Check out this portfolio of AI prompts',
    54→            url: window.location.href
    55→          });
    56→        } catch (err) {
    57→          if (err.name !== 'AbortError') {
    58→            copyLink();
    59→          }
    60→        }
    61→      } else {
    62→        copyLink();
    63→      }
    64→    }
    65→
    66→    async function copyLink() {
    67→      try {
    68→        await navigator.clipboard.writeText(window.location.href);
    69→        const btn = document.querySelector('.btn-copy');
    70→        const originalText = btn.textContent;
    71→        btn.textContent = 'Copied!';
    72→        btn.classList.add('copy-success');
    73→        setTimeout(() => {
    74→          btn.textContent = originalText;
    75→          btn.classList.remove('copy-success');
    76→        }, 2000);
    77→      } catch (err) {
    78→        console.error('Failed to copy:', err);
    79→      }
    80→    }
    81→
    82→    async function copyPrompt(promptId) {
    83→      const card = document.getElementById(promptId);
    84→      const body = card.querySelector('.prompt-body').textContent;
    85→      try {
    86→        await navigator.clipboard.writeText(body);
    87→        const btn = card.querySelector('.btn-copy');
    88→        const originalText = btn.textContent;
    89→        btn.textContent = 'Copied!';
    90→        btn.classList.add('copy-success');
    91→        setTimeout(() => {
    92→          btn.textContent = originalText;
    93→          btn.classList.remove('copy-success');
    94→        }, 2000);
    95→      } catch (err) {
    96→        console.error('Failed to copy:', err);
    97→      }
    98→    }
    99→  </script>
